using Microsoft.AspNetCore.Mvc;

/// <summary>
/// Migrated from ASP.NET Framework WebForms to ASP.NET Core MVC (.NET 8).
///
/// Key changes:
///   1. Response.End()              → removed; just return from the action
///   2. Response.Redirect(url,true) → return RedirectResult (or Redirect helper)
///   3. catch(ThreadAbortException) → removed entirely; no longer thrown
///   4. WebForms event handlers     → MVC action methods returning IActionResult
///   5. Response.Write(data)        → return File() / Content() result
/// </summary>
public class ReportController : Controller
{
    // --- Export endpoint ---
    // BEFORE: Response.Clear/Write/End pattern that relied on Thread.Abort
    // AFTER:  Return a FileContentResult; the framework handles the response lifecycle.
    [HttpPost]
    public IActionResult Export()
    {
        var data = GenerateReport();

        // File() sets Content-Disposition automatically.
        // No need to Clear/End — returning a result ends the response.
        return File(
            System.Text.Encoding.UTF8.GetBytes(data),
            "text/csv",
            "report.csv");
    }

    // --- Redirect endpoint ---
    // BEFORE: Response.Redirect(url, true) + catch(ThreadAbortException)
    // AFTER:  Return Redirect() or RedirectResult; no exceptions involved.
    [HttpPost]
    public IActionResult ProcessAction()
    {
        if (!User.Identity?.IsAuthenticated ?? true)
        {
            // Redirect() returns a 302; no Thread.Abort, no endResponse flag.
            return Redirect("/login");
        }

        try
        {
            ProcessRequest();
            return Redirect("/success");
        }
        // ThreadAbortException catch block removed — it is never thrown in .NET 8.
        // OperationCanceledException is the modern equivalent if you need
        // to handle client disconnects (via HttpContext.RequestAborted).
        catch (Exception ex)
        {
            LogError(ex);
            return Redirect("/error");
        }
    }

    private string GenerateReport() => "col1,col2\nval1,val2";
    private void ProcessRequest() { /* business logic */ }
    private void LogError(Exception ex) { /* logging */ }
}

